+      }),
+    ];
+  }
+}
+
+const styleRecords: {value: LinkStyleValue, description: string}[] = [
+  {value: 'no-change', description: 'Leave existing links unchanged'},
+  {value: 'markdown', description: 'Use Markdown links and images'},
+  {value: 'wiki', description: 'Use Obsidian wiki links and embeds'},
+];
+
+function convertWikiLinksToMarkdown(text: string, options: LinkStyleOptions): string {
+  return text.replace(/(!)?\\[\\[([^\
]*?)\\]\\]/g, (match, embed: string | undefined, contents: string) => {
+    const image = embed === '!';
+    if ((image ? options.imageStyle : options.linkStyle) !== 'markdown') {
+      return match;
+    }
+
+    const separator = contents.indexOf('|');
+    const target = separator === -1 ? contents : contents.slice(0, separator);
+    const display = separator === -1 ? undefined : contents.slice(separator + 1);
+    if (!target) {
+      return match;
+    }
