+    if (image) {
+      const alt = display === undefined || /^\\d+(?:x\\d+)?$/.test(display) ? target : display;
+      return `![${alt}](${target})`;
+    }
+
+    return `[${display ?? defaultHeadingDisplay(target)}](${target})`;
+  });
+}
+
+function convertMarkdownLinksToWiki(text: string, options: LinkStyleOptions): string {
+  let result = '';
+  let index = 0;
+
+  while (index < text.length) {
+    const link = parseMarkdownLink(text, index);
+    if (!link || (link.image ? options.imageStyle : options.linkStyle) !== 'wiki') {
+      result += text[index++];
+      continue;
+    }
+
+    const display = link.image ? imageDisplay(link.label, link.target) : link.label;
+    result += `${link.image ? '!' : ''}[[${link.target}${display ? `|${display}` : ''}]]`;
+    index = link.end;
+  }
+
+  return result;
+}
+
+function parseMarkdownLink(text: string, start: number): MarkdownLink | null {
+  const image = text[start] === '!' && text[start + 1] === '[';
+  const labelStart = image ? start + 1 : start;
+  if (text[labelStart] !== '[' || isEscaped(text, labelStart)) {
+    return null;
+  }
+
+  const labelEnd = findBalancedEnd(text, labelStart, '[', ']');
+  if (labelEnd === -1 || text[labelEnd + 1] !== '(') {
+    return null;
+  }
+  const destinationEnd = findBalancedEnd(text, labelEnd + 1, '(', ')');
+  if (destinationEnd === -1) {
+    return null;
+  }
+
+  const label = text.slice(labelStart + 1, labelEnd);
+  const rawDestination = text.slice(labelEnd + 2, destinationEnd);
+  if (label.includes('\
') || rawDestination.includes('\
')) {
+    return null;
+  }
+  const target = parseDestination(rawDestination);
+  if (!target || target.includes('://')) {
+    return null;
+  }
+
+  return {end: destinationEnd + 1, image, label: unescapeMarkdown(label), target};
+}
+
+function findBalancedEnd(text: string, start: number, open: string, close: string): number {
+  let depth = 0;
+  for (let index = start; index < text.length; index++) {
+    if (isEscaped(text, index)) {
+      continue;
+    }
+    if (text[index] === open) {
+      depth++;
+    } else if (text[index] === close && --depth === 0) {
+      return index;
+    }
+  }
+  return -1;
+}
+
+function parseDestination(rawDestination: string): string | null {
+  const trimmedStart = rawDestination.search(/\\S/);
+  if (trimmedStart === -1) {
+    return null;
+  }
+
+  if (rawDestination[trimmedStart] === '<') {
+    let closingIndex = -1;
+    for (let index = trimmedStart + 1; index < rawDestination.length; index++) {
+      if (rawDestination[index] === '>' && !isEscaped(rawDestination, index)) {
+        closingIndex = index;
+        break;
+      }
+    }
+    if (closingIndex === -1 || !/^\\s*$/.test(rawDestination.slice(closingIndex + 1))) {
+      return null;
+    }
+    return unescapeMarkdown(rawDestination.slice(trimmedStart + 1, closingIndex));
+  }
+
+  if (/\\s/.test(rawDestination.replace(/\\\\./g, ''))) {
+    return null;
+  }
+  return unescapeMarkdown(rawDestination);
+}
+
+function isEscaped(text: string, index: number): boolean {
+  let backslashCount = 0;
+  for (let current = index - 1; current >= 0 && text[current] === '\\\'; current--) {
+    backslashCount++;
+  }
+  return backslashCount % 2 === 1;
+}
+
+function unescapeMarkdown(value: string): string {
+  return value.replace(/\\\\(.)/g, '$1');
+}
+
+function defaultHeadingDisplay(target: string): string {
+  const headingIndex = target.indexOf('#');
+  if (headingIndex === -1) {
+    return target;
+  }
+  const page = target.slice(0, headingIndex);
+  const heading = target.slice(headingIndex + 1);
+  return page ? `${page} > ${heading}` : heading;
+}
+
+function imageDisplay(label: string, target: string): string {
+  return !label || label === target ? '' : label;
+}
